package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonWriterTest {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void testValue_withNonNullString_invokesExpectedMethodsAndReturnsThis() throws Exception {
    // Arrange
    String testValue = "testString";

    // Spy on jsonWriter to verify private method calls
    JsonWriter spyWriter = spy(jsonWriter);

    // Use reflection to make private methods accessible
    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);
    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);
    Method stringMethod = JsonWriter.class.getDeclaredMethod("string", String.class);
    stringMethod.setAccessible(true);

    // Act
    JsonWriter returned = spyWriter.value(testValue);

    // Assert
    assertSame(spyWriter, returned);

    // Verify private methods called once
    verify(spyWriter, times(1)).writeDeferredName();
    verify(spyWriter, times(1)).beforeValue();
    verify(spyWriter, times(1)).string(testValue);
  }

  @Test
  public void testValue_withNullString_callsNullValueAndReturnsResult() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);

    // Stub nullValue to verify it is called
    doReturn(spyWriter).when(spyWriter).nullValue();

    JsonWriter returned = spyWriter.value(null);

    assertSame(spyWriter, returned);
    verify(spyWriter, times(1)).nullValue();
    verify(spyWriter, never()).writeDeferredName();
    verify(spyWriter, never()).beforeValue();
    verify(spyWriter, never()).string(anyString());
  }

  @Test
  public void testValue_multipleCalls_producesExpectedOutput() throws IOException {
    jsonWriter.beginArray();
    jsonWriter.value("one");
    jsonWriter.value("two");
    jsonWriter.endArray();
    jsonWriter.flush();

    String output = stringWriter.toString();
    assertNotNull(output);
    assertTrue(output.contains("one"));
    assertTrue(output.contains("two"));
  }
}

